testCases:
describe('Main heading', () => {
  it('should contain exactly one <h1> element', () => {
    expect(document.querySelectorAll('h1').length).to.equal(1);
  });
});

describe('Heading text', () => {
  it('the <h1> should say "Hello, World!"', () => {
    const h1 = document.querySelector('h1');
    expect(h1).to.exist;
    expect(h1.textContent.trim()).to.equal('Hello, World!');
  });
});

describe('Paragraph count', () => {
  it('should contain exactly two <p> elements', () => {
    expect(document.querySelectorAll('p').length).to.equal(2);
  });
});

describe('First paragraph', () => {
  it('should say "I am learning HTML."', () => {
    const p = document.querySelectorAll('p')[0];
    expect(p).to.exist;
    expect(p.textContent.trim()).to.equal('I am learning HTML.');
  });
});

describe('Second paragraph', () => {
  it('should say "It is fun!"', () => {
    const p = document.querySelectorAll('p')[1];
    expect(p).to.exist;
    expect(p.textContent.trim()).to.equal('It is fun!');
  });
});

describe('Link', () => {
  it('should have an <a> pointing to https://example.com with text "Visit Example"', () => {
    const a = document.querySelector('a');
    expect(a).to.exist;
    expect(a.getAttribute('href')).to.equal('https://example.com');
    expect(a.textContent.trim()).to.equal('Visit Example');
  });
});

describe('Image', () => {
  it('should have an <img> with the correct src', () => {
    const img = document.querySelector('img');
    expect(img).to.exist;
    expect(img.getAttribute('src')).to.equal('https://via.placeholder.com/150');
  });

  it('should have the correct alt text', () => {
    const img = document.querySelector('img');
    expect(img).to.exist;
    expect(img.getAttribute('alt')).to.equal('Placeholder image');
  });
});

describe('Unordered list', () => {
  it('should contain exactly one <ul> element', () => {
    expect(document.querySelectorAll('ul').length).to.equal(1);
  });

  it('should contain exactly three <li> elements inside the <ul>', () => {
    const items = document.querySelectorAll('ul > li');
    expect(items.length).to.equal(3);
  });
});

describe('List items in order', () => {
  it('should list Apple, Banana, Cherry in that order', () => {
    const items = Array.from(document.querySelectorAll('ul > li'))
      .map(li => li.textContent.trim());
    expect(items).to.deep.equal(['Apple', 'Banana', 'Cherry']);
  });
});

describe('Heading color', () => {
  it('the <h1> should be rendered in red', () => {
    const h1 = document.querySelector('h1');
    expect(h1).to.exist;
    const color = getComputedStyle(h1).color;
    expect(color).to.equal('rgb(255, 0, 0)');
  });
});

describe('Body background', () => {
  it('the body should have background color #ffffcc', () => {
    const bg = getComputedStyle(document.body).backgroundColor;
    expect(bg).to.equal('rgb(255, 255, 204)');
  });
});

describe('Paragraph font size', () => {
  it('paragraphs should have a font size of 20px', () => {
    const p = document.querySelector('p');
    expect(p).to.exist;
    expect(getComputedStyle(p).fontSize).to.equal('20px');
  });
});

describe('Highlighted paragraph', () => {
  it('should have a yellow background', () => {
    const el = document.querySelector('p.highlight');
    expect(el).to.exist;
    expect(getComputedStyle(el).backgroundColor).to.equal('rgb(255, 255, 0)');
  });

  it('should be bold', () => {
    const el = document.querySelector('p.highlight');
    expect(el).to.exist;
    const weight = getComputedStyle(el).fontWeight;
    // "bold" computes to 700 in most browsers
    expect(['bold', '700']).to.include(weight);
  });
});

describe('Non-highlighted paragraph', () => {
  it('should NOT have a yellow background', () => {
    const paragraphs = Array.from(document.querySelectorAll('p'));
    const plain = paragraphs.find(p => !p.classList.contains('highlight'));
    expect(plain, 'expected a paragraph without the highlight class').to.exist;
    expect(getComputedStyle(plain).backgroundColor).to.not.equal('rgb(255, 255, 0)');
  });
});

describe('Centered heading', () => {
  it('the <h1> should have text-align center', () => {
    const h1 = document.querySelector('h1');
    expect(h1).to.exist;
    expect(getComputedStyle(h1).textAlign).to.equal('center');
  });
});
